const path = require('path');
const {builder: builderConfig} = new (require('../lib/config'));

const {Config: WebpackConfig, environment} = require('webpack-config');

const HtmlMinifierPlugin = require('./plugins/htmlMinifierPlugin');
const CssMinifierPlugin = require('./plugins/cssMinifierPlugin');
const UglifyJsPlugin = require('uglifyjs-webpack-plugin');

const builderPath = builderConfig.path;

const config = {
    plugins: [
        new HtmlMinifierPlugin(),
        new CssMinifierPlugin(),
        new UglifyJsPlugin({
            uglifyOptions: {
                mangle: false
            }
        })
    ]
};

module.exports = new WebpackConfig().extend(path.join(__dirname, 'webpack.base.config.js')).merge(config);